<script setup lang="ts">import { computed } from 'vue';import type { Agent,Room,RunSnapshot } from '../domain/types';import RoomBuilding from './RoomBuilding.vue';import CentralHall from './CentralHall.vue';const p=defineProps<{teamId:number;rooms:readonly Room[];agents:readonly Agent[];run:RunSnapshot}>();const group=computed(()=>p.rooms.filter(r=>r.type==='group'));const runtime=(id:number)=>p.run.roomRuns[id]||{roomId:id,status:'waiting',progress:0,currentAgentId:null,currentNpcStatus:'idle',activityLabel:'静候差遣',completedTasks:0,totalTasks:0,lastActivityAt:null};const rootRoom=computed(()=>group.value.find(r=>r.tags.includes('root')||r.tags.includes('task'))||group.value[0]);const sideRooms=computed(()=>group.value.filter(r=>r.id!==rootRoom.value?.id));</script>
<template><div class="courtyard-wrap"><div class="mountains" aria-hidden="true"><i></i><i></i><i></i></div><div class="courtyard" aria-label="团队院落鸟瞰图"><div class="path-stone" aria-hidden="true"></div><div v-for="(room,index) in sideRooms" :key="room.id" class="room-slot" :class="`slot-${index%8}`"><RoomBuilding :room="room" :runtime="runtime(room.id)" :agents="agents.filter(a=>room.agentIds.includes(a.id))"/></div><div class="central-slot"><CentralHall :run="run" :rooms="group" :agents="agents"/><RouterLink v-if="rootRoom" class="enter-hall" :to="{name:'room',params:{teamId,roomId:rootRoom.id}}">入殿问策</RouterLink></div></div></div></template>
